var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님! 뒤 조심하세요!","JPN":"先輩！　後ろに気を付けてください！","ENG":"Mina! On your six!","TWN":"前輩，小心背後！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"제법이네, 노엘. 실력이 눈에 띄게 늘었어.","JPN":"やるね、ノエル。実力が目に見えて伸びてるじゃない。","ENG":"Not bad, Noelle. Your skills have greatly improved.","TWN":"不錯，洛艾兒。你進步了不少。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤헷, 다친 팔로도 늘 앞장서시는 선배님에 비하면 아직 멀었지만요.","JPN":"へへっ、怪我した腕でいつも先頭に立っている先輩と比べると、まだまだですけどね。","ENG":"Heheh, but I'm still nowhere close compared to you. You lead people even with a broken arm.","TWN":"嘿嘿，前輩即使手臂受了傷也依然一馬當先，我比你差遠了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저 함선에 다가갈수록… 제가 쓰는 힘도 점점 강해지는 느낌이네요.","JPN":"あの艦船に近づくほど……私が使っている力もどんどん強くなっている気がします。","ENG":"The closer I get to that ship... I can feel that the powers I use are also getting stronger.","TWN":"越是接近那艘艦船……我的力量似乎就會變得越強。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"주의하게. 강해진 힘만큼이나 몸이 감당해야 할 부담도 커질 테니.","JPN":"注意した方がいい。力が強くなった分、体にかかる負担も大きくなるはずだ。","ENG":"Take caution. The stronger the power, the more of a burden it will be on your body.","TWN":"要小心。在力量變強的同時，你的身體也要承擔更大的負擔。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그런데, 사장님까지 같이 가도 괜찮겠어?","JPN":"ところで、社長まで一緒に行ってもいいのか？","ENG":"But was it necessary that you tag along, Boss?","TWN":"對了，老闆真的要一起去嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"스완이 얼마나 강한진 모르지만, 그 여자가 사장님을 노린다면 위험할지도 몰라.","JPN":"スワンがどれほど強いのかはわからないけど、あの女が社長を狙おうとしたら命が危なくなるよ。","ENG":"I don't know how strong Swan is, but you might be in danger if she's after you.","TWN":"我們雖然不知道史旺有多強，但如果她的目標是你，很有可能會陷入危險。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"국제적 유명인사가 날 관중으로 지목했으니, 나도 성의를 보여야지.","JPN":"国際的な有名人が私を観客として名指ししたんだ。こっちも誠意を見せなくては。","ENG":"An international celebrity has appointed me as her audience. I must show some sincerity in return.","TWN":"既然一位國際名人指明我做她的觀眾，我怎能不表現出誠意呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양이야말로 긴장되지 않나?","JPN":"ミナ君こそ、緊張しないのかい？","ENG":"What about you, Mina? Aren't you nervous?","TWN":"反倒是米娜，不緊張嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"안된다고 한다면 거짓말이지.","JPN":"しない、と言ったら嘘になるね。","ENG":"I'd be lying if I said I wasn't.","TWN":"如果說沒有肯定是在撒謊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하지만 세계를 멸망시키려는 음모를 저지하는 일은 전에도 몇 번 겪었으니까.","JPN":"でも、世界を滅ぼそうとする陰謀を阻止することなら、今まで何回も経験したから。","ENG":"But I've had some experience stopping others from destroying the world a few times.","TWN":"但破壞毀滅世界的陰謀這種事，已經不是我第一次經歷了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오오, 선배님의 이런 멋진 멘트를 직접 듣게 되다니!","JPN":"おお、先輩のカッコいいセリフを直接聞けるとは！","ENG":"Ooh! I can't believe I got to hear Mina's cool line in person!","TWN":"哇喔，竟然親耳聽到了前輩如此帥氣的台詞！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 감동했어요!","JPN":"私、感動しました！","ENG":"It's a dream come true!","TWN":"我好感動！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘…","JPN":"ノエル……","ENG":"Noelle...","TWN":"洛艾兒……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"넌 겁나지 않아?","JPN":"あなたは怖くないの？","ENG":"Aren't you even a little scared?","TWN":"你不害怕嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이건 목숨이 걸린 일이야. 태스크포스에 갓 입사한 시골소녀가 감당할만한 일은 아니라고.","JPN":"命がかかっているんだ。タスクフォースに入社したばかりの田舎娘に務まるような仕事ではないんだよ。","ENG":"You're risking your life here. This isn't something that a TASKFORCE rookie can handle.","TWN":"這是生死攸關的時刻，不是剛加入特遣勢力的小女孩所能承受的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 그치만 선배님도 여기에 계신 걸요?","JPN":"はい？　でも先輩もここにいるじゃないですか。","ENG":"What? But you're here too, Mina.","TWN":"嗯？但前輩不也在嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사정이 있으니까.","JPN":"事情があるから。","ENG":"I have my reasons.","TWN":"我有我的理由。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하지만 넌 다르잖아? 굳이 이런 일에 뛰어들지 않아도 돼.","JPN":"でもあなたは違うでしょ？　こんな危ない仕事に首を突っ込まなくてもいいんだ。","ENG":"But it's different for you. You don't need to be here.","TWN":"但你不一樣，你不必捲進這種事情當中。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"덜 위험하고, 더 행복한 미래를 고를 기회가 있다고.","JPN":"より安全で、幸せな未来を選べるチャンスがあるんだよ。","ENG":"You have a chance to choose a happier and less dangerous future for yourself.","TWN":"你可以選擇一個風險更小、更幸福的未來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"동경하고 있으니까요.","JPN":"憧れているからです。","ENG":"It's because I look up to you.","TWN":"但是我很憧憬。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대를 동경하기 때문에 코핀 컴퍼니에 입사했고.","JPN":"フェンリル小隊に憧れてコフィンカンパニーに入社しました。","ENG":"I joined Coffin Company because I looked up to Fenrir Squad.","TWN":"我加入科芬公司是因為我憧憬芬里爾小隊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이런 위험한 순간에도 도망치지 않는 유미나 선배님을 본받고 싶어서 여기까지 따라왔다구요.","JPN":"こんな危険な瞬間でも逃げないミナ先輩のようになりたくて、ここまでついてきたんです。","ENG":"I followed you here so that I could become like you, Mina. Someone who doesn't run away in the face of danger.","TWN":"我跟著大家來到這裡是因為想向臨危不懼的劉米娜前輩學習。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이건 하나부터 열까지 전부 제가 선택한 거예요.","JPN":"これは一から十まで全部、自分で選んだ道です。","ENG":"Everything I did, I chose to do them.","TWN":"從頭到尾都是我自己的選擇。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그러니 제 걱정은 너무 하지 마세요.","JPN":"だから、私の心配はしなくてもいいんですよ。","ENG":"So don't worry too much about me.","TWN":"所以不用太擔心我。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 때문에 선배님이 불안해하는 건 싫어요.","JPN":"私のせいで先輩が不安に思うのは嫌です。","ENG":"I don't want you to be anxious because of me.","TWN":"我不想讓你因為我而感到不安。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"미안. 내가 괜한 소릴 했네.","JPN":"ごめん。余計なことを言ったみたいだね。","ENG":"Sorry. I guess I misspoke.","TWN":"抱歉，是我多嘴了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"대신 다 끝나고 돌아가면, 밥은 내가 살게.","JPN":"代わりに、この事が全部終わって帰ったら、ご飯おごるよ。","ENG":"To make up for that, I'll treat you to a meal once all this is over.","TWN":"等一切結束了，我回去好好請你吃一頓。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 그 말을 들었더니 배고파요!","JPN":"あっ、その話を聞いたらお腹が空いてきました！","ENG":"Oh! Hearing that made me hungry!","TWN":"哎呀，聽你說這話，我肚子餓了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"좀 참아.","JPN":"今は我慢してね。","ENG":"We'll eat later.","TWN":"先忍忍吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어? 방금 무슨 소리가 들리지 않았어요?","JPN":"あれ？　今、何か聞こえませんでした？","ENG":"Huh? Did you hear that?","TWN":"咦？剛才沒聽到什麼嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"경보음이에요. 저 함선 쪽에서 들려왔어요.","JPN":"警報の音ですね。艦船の方から聞こえました。","ENG":"It's an alarm. It's coming from that ship.","TWN":"是警報，從那艦船上發出的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"좋은 징조는 아닌 것 같네요.","JPN":"良い兆しではありませんね。","ENG":"I don't think that's a good sign.","TWN":"這聽起來可不是什麼好兆頭。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"얼마 안 남았어.","JPN":"もう少しだ。","ENG":"We're running out of time.","TWN":"時間不多了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"서두르자.","JPN":"急ごう。","ENG":"Let's hurry.","TWN":"我們快點吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};